var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 멍청한 놈, 여태 죽은 사람을 끌어안고 주저앉아 있었느냐.","JPN":" 愚か者め、まだ死んだ者を抱えてへたり込んでいたのか。","ENG":"Have you been sitting there, clutching a dead body all this time? Fool.","TWN":"愚蠢的傢伙，現在還抱著死人乾坐著嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 결국 마지막까지 미혹에서 벗어나질 못하는군.","JPN":" 結局最後まで魅惑を捨てられないか。","ENG":"So you are unable to resist temptations until the very end.","TWN":"你最終還是沒能做好覺悟啊。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그래. 그렇게 고개 숙이고 있어라. 못미더운 너에게 잘 어울리는 모습이니.","JPN":" そうだ。そうやってこうべを垂れていろ。頼りない貴様にはお似合いの格好だ。","ENG":"Fine. Stay that way, head down. It suits your pathetic state.","TWN":"嗯，你就那樣低著頭吧。這個樣子很適合不可靠的你。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 결국 너에게 마음을 다잡길 바란 것 자체가 과한 기대였겠지.","JPN":" 結局貴様に心を強く持つように望んだことが、無理な期待だったのだ。","ENG":"I was wrong to expect you would toughen up eventually.","TWN":"最終還是希望你能下定決心，這本身就是我的奢望吧。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" 샬롯은…… 어떻게 되었습니까?","JPN":" シャーロットは……どうなりましたか？","ENG":"What happened... to Carlota?","TWN":"夏洛特……怎麼樣了？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 예전처럼 전령 취급이라도 하려는 거냐?","JPN":" 以前のように伝令扱いでもする気か？","ENG":"Are you going to treat me as a messenger again?","TWN":"你又想像以前那樣把我當傳話筒嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 모른다. 전쟁터 한복판에서 작별했으니.","JPN":" 知らん。戦場の真っ只中で別れたからな。","ENG":"I do not know. We parted in the battlefield.","TWN":"不知道。我們已經在戰場中央告別了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" ……알렌은, 어떻게 됐습니까?","JPN":" ……アレンは、どうなりましたか？","ENG":"...What about Allen?","TWN":"……艾倫，怎麼樣了？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 죽었거나, 죽겠지.","JPN":" 死んだか、死ぬだろうな。","ENG":"It is either that he died or will be dead.","TWN":"死了，或者快要死了吧？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 알렌 경이 있는 한 우리 군은 호락호락하지 않으니 말이다.","JPN":" アレンがいる限り、我々の軍はそう簡単には負けない。","ENG":"As long as Sir Allen is with us, our forces will stay strong.","TWN":"只要艾倫卿在，我們的軍隊就會所向披靡。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그나마도 이제는 속수무책으로 무너질 일만 남았겠구나.","JPN":" それでも、もうあっけなく終わりそうだがな。","ENG":"However, it seems that even that will come to crumble down.","TWN":"然而現在只能束手無策地等著毀滅。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" 전하…….","JPN":" 殿下……","ENG":"Your Highness...","TWN":"殿下……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" ……후우.","JPN":" ……ふう。","ENG":"...*Sigh*","TWN":"……呼。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 어리석은 것. 기사가 맹세하는 충성의 서약도 죽음에 이를 때까지거늘.","JPN":" 愚かな奴め。騎士が誓う忠誠の誓約も死ぬまでだというに。","ENG":"Foolish boy. Even when chivalry is vowed upon only until death...","TWN":"愚蠢的傢伙，騎士立下的忠誠誓約到死也就結束了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 망자가 되어서도 너는 여전히 구원자로구나.","JPN":" なのに貴様は、亡者になってからも相変わらず救世主のままだ。","ENG":"You somehow still remain as the Savior after passing.","TWN":"可即使變成死人，你還是我們的救贖者。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 넌 쓸데없이 착한 놈이다. 이런 일을 저지르기에는 어울리지도 않았어.","JPN":" 貴様は無駄に優しい。こんなことをするには向いてなかった。","ENG":"You are too frail. You are not suited for this kind of work.","TWN":"你太過善良，不適合做這種事。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" 전하는 그래서…… 그래서 저를 몰아세우신 겁니까?","JPN":" だからこそ殿下は……僕を責め立てていたんですか？","ENG":"Is that why... you have been lashing at me all this time?","TWN":"所以殿下……才會逼迫我嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그럼 일개 평민 따위가 감당도 못 할 사명에 짓눌려 가는 꼴을, 영원히 구경만 하란 것이냐?","JPN":" ただの平民がどうやっても背負いきれない使命に押しつぶされていく様を、永遠に黙って見ていろというのか？","ENG":"What do you expect? Do you think I'd sit here and watch a mere peasant get smothered by his own calling?","TWN":"那你想怎樣？讓我看著一介平民被不堪重負的使命壓垮而無動於衷嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 마왕이라고 자처하는 자들을 봐라. 너와 같은 자들은 없었느니라.","JPN":" 魔王という連中を見てみろ。貴様のような奴はいなかった。","ENG":"Look at the others who call themselves Demon Lords. Not one of them are like you.","TWN":"看看那些自稱是魔王的傢伙們吧，沒有一個是像你一樣的。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 아카데미에 처박혔을 때는 늦게나마 반항기라도 오는 줄 알았건만…….","JPN":" アカデミーに籠っていた頃は、遅れながらも反抗期が来るものと思っていた時期もあったんだが……","ENG":"I thought you already went through your rebellious phase when you isolated yourself in the academy...","TWN":"在學院裡待著的時候，我還以為你會出現遲來地叛逆期……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 너에게는 자유로워질 용기도 없었더군.","JPN":" 貴様には自由になる勇気すらなかった。","ENG":"But it seems that you don't even have the courage to free yourself.","TWN":"結果你連追尋自由的勇氣都沒有。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그러니 떠나라.","JPN":" だから去れ。","ENG":"Leave.","TWN":"離開吧。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 너의 짐인 우리들은 이제 모두 사라질 테니.","JPN":" 貴様の重荷である我々もこれで消える。","ENG":"We are nothing but a burden on your shoulders. We will perish.","TWN":"拖累你的我們現在全都要消失了。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 아무도 너를 모르는 곳으로 떠나서, 네가 살고 싶은 대로 살아라.","JPN":" 誰も貴様を知らない場所に行き、貴様の自由に生きろ。","ENG":"Leave here and live the life you yearned for, where nobody knows you.","TWN":"去一個沒人認識你的地方，過你想要的生活吧。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" 전하…….","JPN":" 殿下……","ENG":"Your Highness...","TWN":"殿下……"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" 저는……. 저는 전하에게서 구원자의 지위를 훔쳤습니다.","JPN":" 僕は……殿下から救世主の地位を盗みました。","ENG":"I... I took away your title of Savior.","TWN":"我……我從殿下那裡奪走了救贖者的位置。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" 그런데 어째서…… 마지막까지…….","JPN":" なのにどうして……最後まで……","ENG":"But why do you... Until the very end...","TWN":"但是為什麼……到最後……"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 레이. 나는 내가 다스려야 마땅할 제국의 누구도 구하지 못했다.","JPN":" レイ。私は私が治める帝国の誰一人として救う事ができなかった。","ENG":"Ray. I was unable to save a single soul under my jurisdiction.","TWN":"雷伊，我沒能救出我該統治的帝國中的任何人。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_25"},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 네가, 네헤모트의 칼날에 쓰러지지 않았던 너만이.","JPN":" 貴様が、ネヘモトの剣によって倒されなかった貴様だけが。","ENG":"None but you, the sole being who didn't fall beneath the blade of Nehemoth.","TWN":"唯有你，唯有沒有被貝赫莫特的刀刃打倒的你。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_26"},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 내가 구할 수 있는 마지막 신민이었다.","JPN":" 私の救える最後の臣民だった。","ENG":"You were the only subject I was able to save.","TWN":"是我能夠拯救的最後一個百姓。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_27"},{"id":"L39_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 너의 구원이 황족으로서 나의 긍지다.","JPN":" 貴様が救われることが、皇族としての私の誇りだ。","ENG":"Your salvation is my dignity as the royal prince.","TWN":"對你的救贖，是我身為皇室最後的驕傲。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_28"},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" ……전하.","JPN":" ……殿下。","ENG":"...Your Highness.","TWN":"……殿下。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":" 고개를 들었을 때는 아무도 없었다.","JPN":" 顔を上げたとき、そこには誰もいなかった。","ENG":"When I raised my head, there was no one there.","TWN":"當我抬頭時，一個人都沒有。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":" 처음부터, 아무도 없었다.","JPN":" 最初から、誰もいなかった。","ENG":"No one was there, from the very beginning.","TWN":"或許從一開始，就一個人都沒有。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" 전하, 저는…….","JPN":" 殿下、僕は……","ENG":"Your Highness, I...","TWN":"殿下，我……"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" 결국 아무에게도 도움이 되지 못했어요.","JPN":" 結局誰の役にも立ちませんでした。","ENG":"I couldn't help anyone eventually.","TWN":"最終誰都沒能幫到。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" 그렇다면……. 적어도.","JPN":" ならば……せめて。","ENG":"Then... At least...","TWN":"那……至少。"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":" 마지막만큼은…….","JPN":" 最後ぐらいは……","ENG":"At least the end...","TWN":"在最後……"},"stage":{"bg":"THRONE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};